import java.util.*;
import javax.swing.ProgressMonitor;

public class ConcodeState {
    // Fields
    private boolean consoleMode;
    private int maxValue;
    private boolean showProgress;
    private ProgressMonitor progressMonitor;
    private StringBuffer log;
    private String currentMessage;
    private List<String> debugMessages;
    private TreeSet<String> warnings;
    private int curValue;
    private HashMap<String, Integer> warningCounts;

    public ConcodeState() {
        this.consoleMode = false;
        this.maxValue = 100;
        this.showProgress = false;
        this.progressMonitor = null;
        this.log = new StringBuffer();
        this.currentMessage = "";
        this.debugMessages = new ArrayList<>();
        this.warnings = new TreeSet<>();
        this.curValue = 0;
        this.warningCounts = new HashMap<>();
    }

    // Methods inferred from names
    public void setConsoleModeAndParseShowProgress() {
        // Placeholder implementation
    }

    public void setShowProgress(boolean showProgress) {
        this.showProgress = showProgress;
    }

    public void setCurrentMessage(String currentMessage) {
        this.currentMessage = currentMessage;
    }

    public int getMaxValue() {
        return maxValue;
    }

    public String getLog() {
        return log != null ? log.toString() : "";
    }

    public void logWarning(String warning) {
        if (warning != null) {
            warnings.add(warning);
            log.append("WARNING: ").append(warning).append('\n');
        }
    }

    public ArrayList<String> getWarnings() {
        return new ArrayList<>(warnings);
    }

    public void logDebug(String message) {
        if (message != null) {
            debugMessages.add(message);
            log.append("DEBUG: ").append(message).append('\n');
        }
    }

    public ArrayList<String> getMessages() {
        return new ArrayList<>(debugMessages);
    }

    public boolean isConsoleMode() {
        return consoleMode;
    }

    public List<String> getDebugMessages() {
        return new ArrayList<>(debugMessages);
    }

    public void setMaxValue(int maxValue) {
        this.maxValue = maxValue;
    }

    public void incrementCurValue() {
        this.curValue++;
    }

    public boolean isRunningOnServer() {
        // Placeholder: default to false
        return false;
    }

    public String getCurrentMessage() {
        return currentMessage;
    }

    public void setConsoleMode(boolean consoleMode) {
        this.consoleMode = consoleMode;
    }

    public int getCurValue() {
        return curValue;
    }

    public boolean isShowProgress() {
        return showProgress;
    }

    public double getPercentComplete() {
        if (maxValue == 0) return 0.0;
        return (double) curValue / maxValue;
    }
}
